import { CardHeader, IconButton} from '@material-ui/core'
import { DeleteOutlined } from '@material-ui/icons'
import React from 'react'

export default function Card({ subject }) {
    return (
        <div>
            <Card>
                <CardHeader
                    action={
                        <IconButton>
                            <DeleteOutlined />
                        </IconButton>
                    }
                />
            </Card>
        </div>
    )
}
